static int copy_with_flip(const char *src_path, const char *dst_path) {
    FILE *in = fopen(src_path, "rb");
    if (!in) return -1;
    FILE *out = fopen(dst_path, "wb");
    if (!out) { fclose(in); return -2; }
    unsigned char buf[8192];
    size_t total = 0;
