        if (total == 0 && r > 8) {
            buf[8] ^= 0xFFu;
        }
        fwrite(buf, 1, r, out);
        total += r;
    }
    fclose(in);
    fclose(out);
    return 0;
}

int phase_persist(SimState *st, const char *vault_path, const char *tamper_path,
                  const char *log_path, VaultAudit *resume_aud) {
